"""
sloth.py — Paresseux Mascotte Slothia
Mascotte dessinée à la main 🎨
"""

import datetime

SLOTH_IMG_B64 = ""


def get_current_season() -> str:
    month = datetime.datetime.now().month
    if month in [3, 4, 5]:   return "printemps"
    if month in [6, 7, 8]:   return "ete"
    if month in [9, 10, 11]: return "automne"
    return "hiver"


def get_tenue_for_context(context: str) -> str:
    if context == "toxique":   return "toxique"
    if context == "aquatique": return "aquatique"
    if context == "saison":    return get_current_season()
    return "normal"


def _tenue_label(tenue: str) -> str:
    labels = {
        "normal":    "🦥 Slothia",
        "printemps": "🌸 Printemps",
        "ete":       "🌞 Été",
        "automne":   "🍂 Automne",
        "hiver":     "❄️ Hiver",
        "aquatique": "🤿 Aquatique",
        "toxique":   "☣️ Alerte",
    }
    return labels.get(tenue, tenue)


def render_sloth(tenue: str = "normal", pose: str = "idle",
                 message: str = "Heyy… 🦥", height: int = 320) -> str:
    """Retourne le HTML du paresseux dessiné animé."""
    accent_map = {
        "normal": "#6dba6d", "printemps": "#e88fc8", "ete": "#f5c030",
        "automne": "#d4782a", "hiver": "#a8d8f0",
        "aquatique": "#42b4f5", "toxique": "#aaff00"
    }
    accent = accent_map.get(tenue, "#6dba6d")

    pose_anim = {
        "idle":      "float 3.5s ease-in-out infinite",
        "thinking":  "thinking 1.8s ease-in-out infinite",
        "talking":   "talking 0.45s ease-in-out infinite",
        "excited":   "excited 0.35s ease-in-out infinite",
        "surprised": "surprised 0.2s ease-in-out 4",
        "sleepy":    "sleepy 4s ease-in-out infinite",
        "wave":      "wave 1s ease-in-out infinite",
        "alert":     "alert 0.6s ease-in-out infinite",
    }

    img_filter = (
        "drop-shadow(0 4px 20px rgba(170,255,0,0.5))"
        if tenue == "toxique"
        else f"drop-shadow(0 6px 18px {accent}55)"
    )
    anim  = pose_anim.get(pose, pose_anim["idle"])
    label = _tenue_label(tenue)

    html = """<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
  * { margin:0; padding:0; box-sizing:border-box; }
  body {
    background:transparent;
    font-family:'Segoe UI',sans-serif;
    display:flex; flex-direction:column;
    align-items:center; justify-content:flex-start;
    padding:8px;
  }
  @keyframes float     { 0%,100%{transform:translateY(0)}           50%{transform:translateY(-8px)} }
  @keyframes thinking  { 0%,100%{transform:rotate(-8deg) translateY(0)}  50%{transform:rotate(-13deg) translateY(-3px)} }
  @keyframes talking   { 0%,100%{transform:rotate(3deg)}            50%{transform:rotate(-3deg)} }
  @keyframes excited   { 0%,100%{transform:scale(1.08) translateY(0)} 50%{transform:scale(1.13) translateY(-10px)} }
  @keyframes surprised { 0%,100%{transform:scale(1.05) translateX(0)} 50%{transform:scale(1.1) translateX(-6px)} }
  @keyframes sleepy    { 0%,100%{transform:rotate(12deg) translateY(0)} 50%{transform:rotate(14deg) translateY(5px)} }
  @keyframes wave      { 0%,100%{transform:rotate(6deg) translateY(0)} 50%{transform:rotate(-5deg) translateY(-6px)} }
  @keyframes alert     { 0%,100%{transform:scale(1.02)} 50%{transform:scale(1.07)} }
  @keyframes pulse     { 0%,100%{opacity:1} 50%{opacity:0.75} }

  .sloth-wrap {
    cursor: pointer;
    display: flex; align-items:center; justify-content:center;
  }
  .tenue-label {
    font-size: 10px;
    letter-spacing: 1.5px; text-transform: uppercase;
    margin-top: 6px; opacity: 0.85;
  }
  .bubble {
    background: white;
    border-radius: 14px 14px 14px 4px;
    padding: 8px 13px; margin-bottom: 10px;
    font-size: 13px; color: #222; font-weight: 700; line-height: 1.4;
    max-width: 210px; text-align: center;
    animation: pulse 3s ease-in-out infinite;
  }
</style>
</head>
<body>
"""
    html += f'  <div class="bubble" id="bubble" style="border:2px solid {accent}66;box-shadow:0 3px 14px {accent}44">{message}</div>\n'
    html += f'  <div class="sloth-wrap" style="animation:{anim}" onclick="wiggle()">\n'
    html += f'    <img style="width:190px;height:auto;filter:{img_filter}" src="data:image/png;base64,{SLOTH_IMG_B64}" alt="Slothia"/>\n'
    html += f'  </div>\n'
    html += f'  <div class="tenue-label" style="color:{accent}">{label}</div>\n'
    html += """
  <script>
    // Le message est contrôlé uniquement par Streamlit via set_sloth().
    // Le clic sur le paresseux fait juste un petit wiggle amusant.
    function wiggle() {
      const img = document.querySelector('.sloth-wrap');
      img.style.transition = 'transform 0.1s ease';
      img.style.transform = 'rotate(15deg) scale(1.08)';
      setTimeout(() => { img.style.transform = 'rotate(-10deg)'; }, 100);
      setTimeout(() => { img.style.transform = 'rotate(8deg)';  }, 200);
      setTimeout(() => { img.style.transform = 'rotate(0deg) scale(1)'; }, 300);
    }
  </script>
</body>
</html>"""
    return html